"""Extract and validate all scraped HID report descriptors."""
import re
import json

def clean_hex(raw):
    return ''.join(re.findall(r'0x([0-9a-fA-F]{2})', raw)).lower()

base = "https://github.com/sonik-br/lgff_wheel_adapter/blob/main/pico_lgff_wheel_adapter/usb_descriptors.h"
tmff = "https://github.com/Kimplul/hid-tmff2/blob/master/src"
gimx = "https://github.com/matlo/GIMX-firmwares/blob/master"

D = []

def add(name, vid, pid, raw_hex, source):
    h = clean_hex(raw_hex)
    D.append({"name": name, "vid": vid, "pid": pid, "bytes": len(h)//2, "source": source, "hex": h})

